"use client"

import React, { useEffect, useState } from 'react'
import { TrophyIcon, Loader2Icon, XIcon } from 'lucide-react'

interface TestResult {
    id: string
    wpm: number
    accuracy: number
    language: string
    difficulty: string
    createdAt: string
    user: {
        username: string
    }
}

interface LeaderboardModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export function LeaderboardModal({ isOpen, onClose }: LeaderboardModalProps) {
    const [leaderboard, setLeaderboard] = useState<TestResult[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        if (isOpen) {
            setLoading(true)
            fetch('/api/scores')
                .then(res => res.json())
                .then(data => {
                    setLeaderboard(Array.isArray(data) ? data : [])
                    setLoading(false)
                })
                .catch(err => {
                    console.error("Failed to fetch leaderboard", err)
                    setLeaderboard([])
                    setLoading(false)
                })
        }
    }, [isOpen])

    if (!isOpen) return null

    const medals = ['≡ƒÑç', '≡ƒÑê', '≡ƒÑë']

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-background/80 backdrop-blur-sm">
            <div className="glass-panel p-8 max-w-2xl w-full flex flex-col border border-primary/20 shadow-[0_0_50px_rgba(0,255,157,0.1)] relative max-h-[80vh] overflow-hidden">

                <button 
                    onClick={onClose}
                    className="absolute top-4 right-4 p-1.5 rounded-lg text-neutral hover:text-white hover:bg-surface transition-all"
                >
                    <XIcon className="w-5 h-5" />
                </button>

                <div className="flex items-center gap-3 mb-6">
                    <TrophyIcon className="w-7 h-7 text-yellow-400" />
                    <h2 className="text-2xl font-black text-white tracking-wider uppercase">Leaderboard</h2>
                </div>

                {loading ? (
                    <div className="flex justify-center items-center h-48">
                        <Loader2Icon className="w-8 h-8 text-primary animate-spin" />
                    </div>
                ) : (
                    <div className="overflow-y-auto pr-2 custom-scrollbar">
                        {leaderboard.length === 0 ? (
                            <div className="text-center py-12">
                                <TrophyIcon className="w-12 h-12 text-neutral/20 mx-auto mb-4" />
                                <p className="text-neutral/50 font-mono text-sm">No scores recorded yet. Be the first!</p>
                            </div>
                        ) : (
                            <div className="flex flex-col gap-2">
                                {leaderboard.map((entry, index) => (
                                    <div key={entry.id} className={`flex items-center justify-between p-4 rounded-lg border transition-colors ${
                                        index < 3 
                                            ? 'bg-surface border-primary/20 hover:border-primary/40' 
                                            : 'bg-surface/50 border-white/5 hover:border-white/10'
                                    }`}>
                                        <div className="flex items-center gap-4">
                                            <span className="text-xl font-black w-10 text-center">
                                                {index < 3 ? medals[index] : <span className="text-neutral">#{index + 1}</span>}
                                            </span>
                                            <div>
                                                <span className="text-white font-bold tracking-wider text-sm">{entry.user?.username || 'Anonymous'}</span>
                                                <div className="flex gap-2 mt-0.5">
                                                    <span className="text-[10px] font-mono text-neutral bg-background px-1.5 py-0.5 rounded capitalize">{entry.language}</span>
                                                    <span className="text-[10px] font-mono text-neutral bg-background px-1.5 py-0.5 rounded capitalize">{entry.difficulty}</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex gap-6 items-center">
                                            <div className="flex flex-col items-end">
                                                <span className="text-[10px] uppercase tracking-widest text-secondary font-bold">WPM</span>
                                                <span className={`text-xl font-black ${index < 3 ? 'text-primary neon-text-primary' : 'text-white'}`}>{entry.wpm}</span>
                                            </div>
                                            <div className="flex flex-col items-end w-14">
                                                <span className="text-[10px] uppercase tracking-widest text-secondary font-bold">ACC</span>
                                                <span className="text-lg font-bold text-white">{entry.accuracy}%</span>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    )
}

"use client"

import React, { useEffect, useRef, useState } from 'react'
import Editor from '@monaco-editor/react'
import { useTypingStore } from '../store/typingStore'

export function MonacoEditorTyping() {
    const snippet = useTypingStore(state => state.snippet)
    const language = useTypingStore(state => state.language)
    const theme = useTypingStore(state => state.theme)
    const handleKeydown = useTypingStore(state => state.handleKeydown)
    const inputCharIndex = useTypingStore(state => state.inputCharIndex)

    // Map our custom themes to Monaco themes
    const getMonacoTheme = () => {
        if (theme === 'dracula') return 'vs-dark' // Can be customized later with addTheme
        if (theme === 'githubdark') return 'vs-dark'
        return 'vs-dark'
    }

    // We keep track of user input matching the snippet.
    // In actual VS Code mode, we can either read-only and highlight,
    // or capture global keystrokes exactly like standard mode.
    // Let's use it as a read-only display that highlights text,
    // and rely on the same global key listener in `page.tsx` or `TypingArena`.

    return (
        <div className="glass-panel p-4 h-[400px] overflow-hidden rounded-xl border border-white/10">
             <Editor
                height="100%"
                defaultLanguage={language}
                language={language}
                theme={getMonacoTheme()}
                value={snippet.slice(0, inputCharIndex) + 'Γûê\n\n' + snippet}
                options={{
                    readOnly: true,
                    minimap: { enabled: false },
                    fontSize: 16,
                    lineNumbers: 'on',
                    wordWrap: 'on',
                    cursorBlinking: 'smooth',
                    guides: { indentation: true },
                    scrollBeyondLastLine: false,
                }}
            />
        </div>
    )
}

"use client"

import React, { useEffect, useRef, useState } from 'react'
import { useTypingStore } from '../store/typingStore'
import { gsap } from 'gsap'

export function TypingArena() {
    const containerRef = useRef<HTMLDivElement>(null)
    const [tabPressed, setTabPressed] = useState(false)

    const snippet = useTypingStore(state => state.snippet)
    const inputCharIndex = useTypingStore(state => state.inputCharIndex)
    const errors = useTypingStore(state => state.errors)
    const status = useTypingStore(state => state.status)
    const handleKeydown = useTypingStore(state => state.handleKeydown)
    const resetTest = useTypingStore(state => state.resetTest)
    const fetchSnippet = useTypingStore(state => state.fetchSnippet)
    const getProgress = useTypingStore(state => state.getProgress)

    const progress = getProgress()

    useEffect(() => {
        if (status === 'idle') {
            fetchSnippet()
        }
    }, [status, fetchSnippet])

    useEffect(() => {
        const handleGlobalKeydown = (e: KeyboardEvent) => {
            if (e.ctrlKey || e.metaKey || e.altKey) return

            // Tab+Enter restart
            if (e.key === 'Tab') {
                e.preventDefault()
                setTabPressed(true)
                setTimeout(() => setTabPressed(false), 1500)
                return
            }

            if (e.key === 'Enter') {
                e.preventDefault()
                if (tabPressed) {
                    setTabPressed(false)
                    resetTest()
                }
                return
            }

            handleKeydown(e.key)

            // Error shake animation
            const currentState = useTypingStore.getState()
            if (e.key.length === 1) {
                const chars = currentState.snippet.split('')
                const prevIndex = currentState.inputCharIndex - 1
                if (prevIndex >= 0 && currentState.errors.includes(prevIndex)) {
                    if (containerRef.current) {
                        gsap.fromTo(containerRef.current,
                            { x: -4 },
                            {
                                x: 4, duration: 0.05, yoyo: true, repeat: 3, ease: 'power1.inOut',
                                onComplete: () => {
                                    gsap.set(containerRef.current, { x: 0 })
                                }
                            }
                        )
                    }
                }
            }
        }

        if (status === 'running' || status === 'idle') {
            window.addEventListener('keydown', handleGlobalKeydown)
        }

        return () => {
            window.removeEventListener('keydown', handleGlobalKeydown)
        }
    }, [status, handleKeydown, tabPressed, resetTest])

    // Intro Animation
    useEffect(() => {
        if (containerRef.current) {
            gsap.from(containerRef.current, {
                duration: 1,
                y: 40,
                opacity: 0,
                scale: 0.98,
                ease: "back.out(1.5)"
            })
        }
    }, [])

    if (!snippet) {
        return (
            <div className="glass-panel p-8 md:p-12 animate-shimmer">
                <div className="flex flex-wrap gap-2">
                    {Array.from({ length: 20 }).map((_, i) => (
                        <div key={i} className="h-6 bg-white/5 rounded" style={{ width: `${Math.random() * 60 + 30}px` }}></div>
                    ))}
                </div>
            </div>
        )
    }

    return (
        <div className="relative">
            {/* Progress bar */}
            {status === 'running' && (
                <div className="absolute -top-1 left-0 right-0 h-1 bg-surface rounded-full overflow-hidden">
                    <div
                        className="progress-bar h-full rounded-full"
                        style={{ width: `${progress}%` }}
                    ></div>
                </div>
            )}

            <div
                ref={containerRef}
                className="glass-panel p-8 md:p-12 font-mono text-lg md:text-2xl tracking-wide leading-relaxed shadow-2xl relative outline-none"
                tabIndex={0}
            >
                {/* Tab indicator */}
                {tabPressed && (
                    <div className="absolute top-3 right-4 text-xs font-mono text-primary animate-pulse">
                        press Enter to restart
                    </div>
                )}

                <div className="flex flex-wrap relative">
                    {snippet.split('').map((char, index) => {
                        let colorClass = "text-[var(--color-text-neutral)]"

                        if (index < inputCharIndex) {
                            if (errors.includes(index)) {
                                colorClass = "text-red-500 bg-red-500/20 neon-text-error rounded-sm border-b-2 border-red-500"
                            } else {
                                colorClass = "text-white neon-text-primary"
                            }
                        }

                        const isCurrentChar = index === inputCharIndex

                        return (
                            <span key={index} className="relative">
                                {isCurrentChar && status !== 'finished' && (
                                    <span className="absolute left-0 bottom-0 w-full h-[3px] bg-primary animate-pulse-fast rounded-sm block" style={{ boxShadow: '0 0 8px rgba(0,255,157,0.6)' }}></span>
                                )}
                                <span className={`transition-colors duration-100 ease-out select-none ${colorClass}`}>
                                    {char === " " ? "\u00A0" : char}
                                </span>
                            </span>
                        )
                    })}
                </div>
            </div>
        </div>
    )
}

// Very simple web audio API sound effects so we don't depend on external files

let audioCtx: AudioContext | null = null

function getContext() {
  if (typeof window === 'undefined') return null
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)()
  }
  return audioCtx
}

export function playKeySound() {
  const ctx = getContext()
  if (!ctx) return

  const osc = ctx.createOscillator()
  const gain = ctx.createGain()

  osc.type = 'sine'
  osc.frequency.setValueAtTime(400, ctx.currentTime)
  osc.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 0.05)

  gain.gain.setValueAtTime(0.1, ctx.currentTime)
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.05)

  osc.connect(gain)
  gain.connect(ctx.destination)

  osc.start()
  osc.stop(ctx.currentTime + 0.05)
}

export function playErrorSound() {
  const ctx = getContext()
  if (!ctx) return

  const osc = ctx.createOscillator()
  const gain = ctx.createGain()

  osc.type = 'sawtooth'
  osc.frequency.setValueAtTime(150, ctx.currentTime)
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.1)

  gain.gain.setValueAtTime(0.15, ctx.currentTime)
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1)

  osc.connect(gain)
  gain.connect(ctx.destination)

  osc.start()
  osc.stop(ctx.currentTime + 0.1)
}

export function playSuccessSound() {
  const ctx = getContext()
  if (!ctx) return

  const osc = ctx.createOscillator()
  const gain = ctx.createGain()

  osc.type = 'sine'
  osc.frequency.setValueAtTime(440, ctx.currentTime)
  osc.frequency.setValueAtTime(554.37, ctx.currentTime + 0.1)
  osc.frequency.setValueAtTime(659.25, ctx.currentTime + 0.2)

  gain.gain.setValueAtTime(0, ctx.currentTime)
  gain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + 0.05)
  gain.gain.setValueAtTime(0.1, ctx.currentTime + 0.2)
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.4)

  osc.connect(gain)
  gain.connect(ctx.destination)

  osc.start()
  osc.stop(ctx.currentTime + 0.4)
}

import { create } from 'zustand'

export type TestStatus = 'idle' | 'running' | 'finished'

interface TypingState {
    // Test Configuration
    language: string
    difficulty: string
    timeLimit: number // seconds
    setLanguage: (lang: string) => void
    setDifficulty: (diff: string) => void
    setTimeLimit: (limit: number) => void
    // Phase 1: Editor & Experience
    theme: string
    vsCodeMode: boolean
    soundEnabled: boolean
    setTheme: (theme: string) => void
    setVsCodeMode: (enabled: boolean) => void
    setSoundEnabled: (enabled: boolean) => void

    // Active Test State
    status: TestStatus
    snippet: string
    snippetId: string | null
    inputCharIndex: number
    errors: number[]
    startTime: number | null
    timeRemaining: number

    // Actions
    fetchSnippet: () => Promise<void>
    startTest: () => void
    endTest: () => void
    resetTest: () => void
    handleKeydown: (key: string) => void
    tickTime: () => void

    // Computed metrics
    getWPM: () => number
    getAccuracy: () => number
    getProgress: () => number
}

export const useTypingStore = create<TypingState>((set, get) => ({
    language: 'javascript',
    difficulty: 'intermediate',
    timeLimit: 30,

    theme: 'dracula',
    vsCodeMode: false,
    soundEnabled: true,

    status: 'idle',
    snippet: '',
    snippetId: null,
    inputCharIndex: 0,
    errors: [],
    startTime: null,
    timeRemaining: 30,

    setLanguage: (lang) => set({ language: lang }),
    setDifficulty: (diff) => set({ difficulty: diff }),
    setTimeLimit: (limit) => set({ timeLimit: limit, timeRemaining: limit }),
    setTheme: (theme) => set({ theme }),
    setVsCodeMode: (vsCodeMode) => set({ vsCodeMode }),
    setSoundEnabled: (soundEnabled) => set({ soundEnabled }),

    fetchSnippet: async () => {
        const { language, difficulty } = get()
        try {
            const res = await fetch(`/api/snippets?language=${language}&difficulty=${difficulty}`)
            if (res.ok) {
                const data = await res.json()
                set({ snippet: data.content, snippetId: data.id })
            }
        } catch (error) {
            console.error("Failed to fetch snippet", error)
            // Fallback snippet
            set({
                snippet: "The quick brown fox jumps over the lazy dog.",
                snippetId: null
            })
        }
    },

    startTest: () => set({
        status: 'running',
        inputCharIndex: 0,
        errors: [],
        startTime: Date.now(),
        timeRemaining: get().timeLimit
    }),

    endTest: () => {
        const state = get()
        set({ status: 'finished' })

        if (state.soundEnabled) {
            import('../lib/sound').then(mod => mod.playSuccessSound())
        }

        // Submit score
        if (state.snippetId && state.getWPM() > 0) {
            fetch('/api/scores', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    snippetId: state.snippetId,
                    language: state.language,
                    difficulty: state.difficulty,
                    wpm: state.getWPM(),
                    cpm: state.inputCharIndex,
                    accuracy: state.getAccuracy(),
                    timeTaken: state.timeLimit - state.timeRemaining,
                    mistakes: state.errors
                })
            }).catch(error => {
                console.error("Failed to submit score", error)
            })
        }
    },

    resetTest: () => {
        set((state) => ({
            status: 'idle',
            inputCharIndex: 0,
            errors: [],
            startTime: null,
            timeRemaining: state.timeLimit,
            snippet: '',
            snippetId: null,
        }))
        get().fetchSnippet()
    },

    tickTime: () => {
        const { status, timeRemaining } = get()
        if (status === 'running' && timeRemaining > 0) {
            set({ timeRemaining: timeRemaining - 1 })
        } else if (status === 'running' && timeRemaining <= 0) {
            get().endTest()
        }
    },

    handleKeydown: (key) => {
        const state = get()
        const { status, snippet, inputCharIndex, errors, startTest } = state

        // Start test on first keypress if idle
        if (status === 'idle') {
            startTest()
            // Process the key that started the test immediately
            // Re-read state after startTest since it was just set
        }

        // Re-read the current status after potential state change
        const currentStatus = get().status
        if (currentStatus !== 'running') return

        const currentIndex = get().inputCharIndex
        const currentErrors = get().errors

        // Allow backspace
        if (key === 'Backspace') {
            set({
                inputCharIndex: Math.max(0, currentIndex - 1),
                errors: currentErrors.filter((errIdx) => errIdx !== currentIndex - 1)
            })
            return
        }

        // Ignore modifiers and extra keys
        if (key.length > 1) return

        const expectedChar = snippet[currentIndex]

        if (key === expectedChar) {
            if (state.soundEnabled) {
                import('../lib/sound').then(mod => mod.playKeySound())
            }
            set({ inputCharIndex: currentIndex + 1 })
        } else {
            if (state.soundEnabled) {
                import('../lib/sound').then(mod => mod.playErrorSound())
            }
            set({
                inputCharIndex: currentIndex + 1,
                errors: [...currentErrors, currentIndex]
            })
        }

        // End test if reached the end of the snippet
        if (get().inputCharIndex >= snippet.length) {
            get().endTest()
        }
    },

    getWPM: () => {
        const { startTime, inputCharIndex, errors } = get()
        if (!startTime) return 0

        const minutes = (Date.now() - startTime) / 60000
        if (minutes === 0) return 0

        const correctChars = inputCharIndex - errors.length
        const wpm = (correctChars / 5) / minutes
        return Math.max(0, Math.round(wpm))
    },

    getAccuracy: () => {
        const { inputCharIndex, errors } = get()
        if (inputCharIndex === 0) return 100

        const correctChars = inputCharIndex - errors.length
        const acc = (correctChars / inputCharIndex) * 100
        return Math.max(0, Math.round(acc * 10) / 10)
    },

    getProgress: () => {
        const { inputCharIndex, snippet } = get()
        if (!snippet || snippet.length === 0) return 0
        return Math.round((inputCharIndex / snippet.length) * 100)
    }
}))
